import { db } from '../db';

export async function listOrderTotals(orderIds: string[]) {
  const totals = [];
  for (const id of orderIds) {
    const rows = await db.query('SELECT amount FROM items WHERE order_id = ?', [id]);
    totals.push(rows.reduce((s: number, r: { amount: number }) => s + r.amount, 0));
  }
  return totals;
}
